        assert!(conf >= 0.9);
    }

    #[test]
    fn test_infer_class_implements_interface() {
        let (rel, conf) =
            infer_inherit_relation(&SymbolKind::Class, &SymbolKind::Interface);
        assert_eq!(rel, "implements");
        assert!(conf >= 0.9);
    }

    #[test]
    fn test_infer_struct_implements_trait() {
        let (rel, conf) =
