//! 代码质量指标
//!
//! 提供单一符号和批量代码质量指标计算：
//! - **圈复杂度** — 基于 AST 分支节点计数的控制流复杂度
//! - **出入度** — 基于调用图的 fan-in / fan-out 统计
//! - **继承深度** — 基于类型层次图的继承链深度
//! - **死代码检测** — 基于调用图可达性分析

use std::collections::{HashSet, VecDeque};

use codeconnect_core::error::CodeConnectError;
use codeconnect_core::types::Symbol;

use crate::call_graph::CallGraph;
use crate::type_hierarchy::TypeHierarchy;

/// 代码质量指标
///
/// 汇总单个符号的复杂度、耦合度、继承深度等指标。
#[derive(Debug, Clone)]
pub struct CodeMetrics {
    /// 符号唯一 ID
    pub symbol_id: String,
    /// 符号名称
    pub name: String,
    /// 圈复杂度（基于分支节点统计）
    pub cyclomatic_complexity: u64,
    /// 入度（被其他符号调用的次数）
    pub fan_in: u64,
    /// 出度（调用其他符号的次数）
    pub fan_out: u64,
    /// 继承深度（从当前类型到继承树根的距离）
    pub depth_of_inheritance: u64,
}

/// 死代码条目
///
/// 表示一个从入口点不可达的、可能为死代码的符号。
#[derive(Debug, Clone)]
pub struct DeadCodeEntry {
    /// 符号唯一 ID
    pub symbol_id: String,
    /// 符号名称
    pub name: String,
    /// 置信度 0.0-1.0，值越低越可能是死代码
    /// 1.0 = 完全不可达（肯定是死代码）
    /// 0.5 = 可能存在间接引用但未检测到
    pub confidence: f64,
    /// 标记为死代码的原因描述
    pub reason: String,
}

/// 指标计算器
///
/// 提供批量计算和死代码检测功能。
/// 自身不维护状态，所有方法均为纯函数。
pub struct MetricCalculator;

impl MetricCalculator {
    // ========================================================================
    // 圈复杂度
    // ========================================================================

    /// 计算单个符号的圈复杂度
    ///
    /// ## 算法
    /// 1. 如果 `symbol.complexity` 已有值，直接返回（来自解析器的预计算结果）
    /// 2. 否则对 `source` 文本进行轻量级分析，统计分支关键字：
    ///    - 条件分支: `if`, `else if`
    ///    - 循环: `for`, `while`, `loop`
    ///    - 模式匹配: `match`, `case`, `switch`
    ///    - 异常处理: `catch`, `except`, `rescue`
    ///    - 逻辑运算符（短路求值）: `&&`, `||`
    ///    - 空值合并: `?.`, `??`
    ///    - 三元运算符: `?`
    /// 3. 圈复杂度 = 1（函数入口） + 分支节点总数
    pub fn compute_complexity(symbol: &Symbol, source: &str) -> u64 {
        // 优先使用解析器预计算的值
        if let Some(complexity) = symbol.complexity {
            return complexity;
        }

        // 对源文本做词法级别的分支关键字计数
        let mut complexity: u64 = 1; // 函数入口基准值

        // 使用简单的空格分隔进行词法分析（非完整解析，但足够准确）
        let tokens: Vec<&str> = source
            .split(|c: char| c.is_whitespace() || c == '(' || c == ')' || c == '{' || c == '}' || c == ';' || c == ',')
            .filter(|s| !s.is_empty())
            .collect();

        for &token in &tokens {
            match token {
                // 条件分支
                "if" | "elif" | "elsif" | "elseif" => complexity += 1,
                // 循环
                "for" | "while" | "loop" => complexity += 1,
                // 模式匹配
                "match" | "case" | "switch" => complexity += 1,
                // 异常处理
                "catch" | "except" | "rescue" | "finally" => complexity += 1,
                // 逻辑运算符（短路求值产生分支）
                "&&" | "||" => complexity += 1,
                _ => {}
            }
        }

        // 统计三元运算符 `?`（在 token 中单独出现）
        complexity += tokens.iter().filter(|&&t| t == "?").count() as u64;

        // 统计空值合并运算符 `??` 和可选链 `?.`
        // 这需要在原始源文本上统计
        complexity += source.matches("??").count() as u64;
        complexity += source.matches("?.").count() as u64;

        complexity
    }

    // ========================================================================
    // 批量指标计算
    // ========================================================================

    /// 批量计算所有符号的代码质量指标
    ///
    /// ## 计算内容
    /// - **圈复杂度** — 从 `symbol.complexity` 字段获取（解析器预计算）
    /// - **fan_in** — 调用图中指向当前符号的入边数量
    /// - **fan_out** — 调用图中从当前符号出发的出边数量
    /// - **继承深度** — 类型层次图中当前符号到根的距离
    pub fn compute_all(
        symbols: &[Symbol],
        call_graph: &CallGraph,
        type_hierarchy: &TypeHierarchy,
    ) -> Vec<CodeMetrics> {
        symbols
            .iter()
            .map(|symbol| {
                // 圈复杂度：优先用预计算值，否则默认为 1
                let cyclomatic_complexity = symbol.complexity.unwrap_or(1);

                // 出入度：从调用图获取
                let (fan_in, fan_out) = call_graph.degree(&symbol.name);

                // 继承深度：从类型层次图计算祖先数量
                let ancestors = type_hierarchy.get_ancestors(&symbol.name);
                let depth_of_inheritance = ancestors.len() as u64;

                CodeMetrics {
                    symbol_id: symbol.id.clone(),
                    name: symbol.name.clone(),
                    cyclomatic_complexity,
                    fan_in,
                    fan_out,
                    depth_of_inheritance,
                }
            })
            .collect()
    }

    // ========================================================================
    // 死代码检测
    // ========================================================================

    /// 检测死代码
    ///
    /// ## 算法
    /// 从入口点（main 函数、导出的 pub 函数等）出发，在调用图上做反向 BFS
    /// 可达性分析。即从每个入口点开始，沿"被调用者→调用者"方向（入边）遍历，
    /// 将能到达的节点标记为"可达"。
    ///
    /// 最后，所有未被标记为可达的符号即为**可能死代码**。
    ///
    /// ## 置信度计算
    /// - 1.0 — 完全不可达（没有任何入边）
    /// - 0.8 — 不可达但至少有一条入边（可能是反射/回调等间接调用）
    /// - 0.5 — 不可达但名称匹配常见模式（如 `test_*`）
    pub fn detect_dead_code(
        all_symbols: &[String],
        call_graph: &CallGraph,
        entry_points: &[String],
    ) -> Vec<DeadCodeEntry> {
        // 第1步: 构建可达性集合
        let mut reachable = HashSet::new();
        let mut queue = VecDeque::new();

        // 从入口点开始
        for entry in entry_points {
            reachable.insert(entry.clone());
            queue.push_back(entry.clone());
        }

        // BFS 反向遍历：从调用者沿入边找到被调用的符号
        while let Some(current) = queue.pop_front() {
            // 获取调用 current 的所有符号（调用者）
            let callers = call_graph.get_callers(&current);
            for caller in callers {
                if reachable.insert(caller.clone()) {
                    queue.push_back(caller);
                }
            }
        }

        // 第2步: 找出不可达符号并计算置信度
        let mut dead_entries = Vec::new();
        for symbol_name in all_symbols {
            if reachable.contains(symbol_name.as_str()) {
                continue;
            }

            let (fan_in, _fan_out) = call_graph.degree(symbol_name);

            // 确定置信度和原因
            let (confidence, reason) = if fan_in == 0 {
                // 完全孤立
                (1.0, "从任何入口点都不可达，且未被任何符号调用".to_string())
            } else if symbol_name.starts_with("test_") || symbol_name.contains("_test") {
                // 可能是测试代码
                (0.5, "未被入口点可达，但名称匹配测试模式".to_string())
            } else if symbol_name.starts_with('_') {
                // 可能是内部/私有函数
                (0.7, "未被入口点可达，名称前缀暗示内部函数".to_string())
            } else {
                // 有入边但不可达（可能是反射、动态调用等）
                (0.8, format!(
                    "未被入口点可达，但被 {} 个符号调用（可能是间接/动态调用）",
                    fan_in
                ))
            };

            dead_entries.push(DeadCodeEntry {
                symbol_id: format!("dead_{}", symbol_name),
                name: symbol_name.clone(),
                confidence,
                reason,
            });
        }

        dead_entries
    }
}

