    /// 创建测试用 Symbol
    fn make_symbol(id: &str, name: &str, complexity: Option<u64>) -> Symbol {
        Symbol {
            id: id.to_string(),
            name: name.to_string(),
            kind: SymbolKind::Function,
            location: SourceLocation {
                file_path: "test.rs".to_string(),
                line: 1,
                column: 1,
                end_line: 1,
                end_column: 1,
            },
            signature: None,
            doc_comment: None,
            parent_id: None,
            modifiers: vec![],
            is_exported: false,
            complexity,
        }
    }

