//! 符号级调用图
//!
//! 基于 petgraph 构建的符号间调用关系图，
//! 支持 BFS/DFS 遍历、双向查询（调用者/被调用者），
//! 以及出入度统计。

use std::collections::{HashMap, HashSet, VecDeque};

use codeconnect_core::error::CodeConnectError;
use codeconnect_core::types::{CallEdge, CallType, Symbol};
use codeconnect_index::sled_store::SledStore;
use petgraph::graph::DiGraph;
use petgraph::visit::{Bfs, Dfs, EdgeRef};
use petgraph::Direction;

/// 调用边（图内部使用的精简版）
#[derive(Debug, Clone)]
pub struct CallEdgeData {
    /// 调用类型
    pub call_type: CallType,
    /// 置信度
    pub confidence: f64,
}

/// 调用图中的节点数据
#[derive(Debug, Clone)]
pub struct CallNodeData {
    /// 符号名称
    pub name: String,
    /// 符号类型
    pub kind: String,
    /// 文件路径
    pub file_path: String,
}

/// 符号级调用图
///
/// 有向图：边从调用者指向被调用者。
/// `callee` ← `caller`（箭头方向 = 调用方向）。
pub struct CallGraph {
    /// petgraph 有向图
    graph: DiGraph<CallNodeData, CallEdgeData>,
    /// 符号名到图节点索引的映射
    name_to_id: HashMap<String, petgraph::graph::NodeIndex>,
}

impl CallGraph {
    /// 创建空的调用图
    pub fn new() -> Self {
        Self {
            graph: DiGraph::new(),
            name_to_id: HashMap::new(),
        }
    }

    /// 从 sled 存储构建调用图
    ///
    /// 扫描 edges 命名空间中的所有 CallEdge，构建完整的调用关系图。
    pub fn build_from_sled(sled: &SledStore) -> Result<Self, CodeConnectError> {
        let mut cg = Self::new();

        // 扫描所有调用边
        let prefix = b"edges:";
        for item in sled.scan_prefix(prefix) {
            let (_key, value) =
                item.map_err(|e| CodeConnectError::Index(format!("扫描调用边失败: {}", e)))?;

            let edge: CallEdge = serde_json::from_slice(&value)
                .map_err(|e| CodeConnectError::Index(format!("反序列化调用边失败: {}", e)))?;

            // 确保节点存在
            if cg.name_to_id.get(&edge.caller_id).is_none() {
                cg.graph.add_node(CallNodeData {
                    name: edge.caller_id.clone(),
                    kind: "unknown".to_string(),
                    file_path: edge.location.file_path.clone(),
                });
                cg.name_to_id.insert(
                    edge.caller_id.clone(),
                    petgraph::graph::NodeIndex::new(cg.graph.node_count() - 1),
                );
            }
            if cg.name_to_id.get(&edge.callee_id).is_none() {
                cg.graph.add_node(CallNodeData {
                    name: edge.callee_id.clone(),
                    kind: "unknown".to_string(),
                    file_path: edge.location.file_path.clone(),
                });
                cg.name_to_id.insert(
                    edge.callee_id.clone(),
                    petgraph::graph::NodeIndex::new(cg.graph.node_count() - 1),
                );
            }

            // 添加边
            let caller = cg.name_to_id[&edge.caller_id];
            let callee = cg.name_to_id[&edge.callee_id];
            cg.graph.add_edge(
                caller,
                callee,
                CallEdgeData {
                    call_type: edge.call_type,
                    confidence: edge.confidence,
                },
            );
        }

        Ok(cg)
    }

    /// 便捷方法：只用名字添加调用边（用于测试）
    pub fn add_edge_raw(&mut self, caller: &str, callee: &str) {
        // 确保节点存在
        if !self.name_to_id.contains_key(caller) {
            let idx = self.graph.add_node(CallNodeData {
                name: caller.to_string(),
                kind: "function".to_string(),
                file_path: "test.rs".to_string(),
            });
            self.name_to_id.insert(caller.to_string(), idx);
        }
        if !self.name_to_id.contains_key(callee) {
            let idx = self.graph.add_node(CallNodeData {
                name: callee.to_string(),
                kind: "function".to_string(),
                file_path: "test.rs".to_string(),
            });
            self.name_to_id.insert(callee.to_string(), idx);
        }

        let caller_idx = self.name_to_id[caller];
        let callee_idx = self.name_to_id[callee];
        self.graph.add_edge(
            caller_idx,
            callee_idx,
            CallEdgeData {
                call_type: CallType::Direct,
                confidence: 1.0,
            },
        );
    }

    /// 获取指定符号的出度（调用其他符号的次数）和入度（被其他符号调用的次数）
    pub fn degree(&self, name: &str) -> (u64, u64) {
        let idx = match self.name_to_id.get(name) {
            Some(i) => *i,
            None => return (0, 0),
        };

        let fan_in = self.graph.edges_directed(idx, Direction::Incoming).count() as u64;
        let fan_out = self.graph.edges_directed(idx, Direction::Outgoing).count() as u64;
        (fan_in, fan_out)
    }

    /// 获取所有调用者（入边方向）
    pub fn get_callers(&self, name: &str) -> Vec<String> {
        let idx = match self.name_to_id.get(name) {
            Some(i) => *i,
            None => return Vec::new(),
        };

        self.graph
            .edges_directed(idx, Direction::Incoming)
            .map(|e| self.graph[e.source()].name.clone())
            .collect()
    }

    /// 获取所有被调用者（出边方向）
    pub fn get_callees(&self, name: &str) -> Vec<String> {
        let idx = match self.name_to_id.get(name) {
            Some(i) => *i,
            None => return Vec::new(),
        };

        self.graph
            .edges_directed(idx, Direction::Outgoing)
            .map(|e| self.graph[e.target()].name.clone())
            .collect()
    }

    /// BFS 遍历从指定符号出发可到达的所有符号
    pub fn bfs_reachable(&self, start_name: &str) -> Vec<String> {
        let start = match self.name_to_id.get(start_name) {
            Some(i) => *i,
            None => return Vec::new(),
        };

        let mut bfs = Bfs::new(&self.graph, start);
        let mut result = Vec::new();
        while let Some(node) = bfs.next(&self.graph) {
            result.push(self.graph[node].name.clone());
        }
        result
    }

    /// DFS 遍历从指定符号出发可到达的所有符号
    pub fn dfs_reachable(&self, start_name: &str) -> Vec<String> {
        let start = match self.name_to_id.get(start_name) {
            Some(i) => *i,
            None => return Vec::new(),
        };

        let mut dfs = Dfs::new(&self.graph, start);
        let mut result = Vec::new();
        while let Some(node) = dfs.next(&self.graph) {
            result.push(self.graph[node].name.clone());
        }
        result
    }

    /// 获取图中节点总数
    pub fn node_count(&self) -> usize {
        self.graph.node_count()
    }

    /// 获取图中边总数
    pub fn edge_count(&self) -> usize {
        self.graph.edge_count()
    }
}

// ============================================================================
// 默认实现
// ============================================================================

impl Default for CallGraph {
    fn default() -> Self {
        Self::new()
    }
}

// ============================================================================
// 单元测试
// ============================================================================

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_empty_call_graph() {
        let cg = CallGraph::new();
        assert_eq!(cg.node_count(), 0);
        assert_eq!(cg.edge_count(), 0);
        assert_eq!(cg.degree("nonexistent"), (0, 0));
        assert!(cg.get_callers("nonexistent").is_empty());
        assert!(cg.get_callees("nonexistent").is_empty());
    }

    #[test]
    fn test_add_edge_and_degree() {
        let mut cg = CallGraph::new();
        cg.add_edge_raw("main", "helper");
        cg.add_edge_raw("main", "logger");
        cg.add_edge_raw("helper", "logger");
        cg.add_edge_raw("orphan", "logger");

        assert_eq!(cg.node_count(), 4);
        assert_eq!(cg.edge_count(), 4);

        assert_eq!(cg.degree("main"), (0, 2));
        assert_eq!(cg.degree("helper"), (1, 1));
        assert_eq!(cg.degree("logger"), (3, 0));
        assert_eq!(cg.degree("orphan"), (0, 1));
    }

    #[test]
    fn test_get_callers_and_callees() {
        let mut cg = CallGraph::new();
        cg.add_edge_raw("A", "B");
        cg.add_edge_raw("A", "C");
        cg.add_edge_raw("B", "C");

        let callers_a = cg.get_callers("A");
        assert!(callers_a.is_empty());

        let callers_c = cg.get_callers("C");
        assert_eq!(callers_c.len(), 2);
        assert!(callers_c.contains(&"A".to_string()));
        assert!(callers_c.contains(&"B".to_string()));

        let callees_a = cg.get_callees("A");
        assert_eq!(callees_a.len(), 2);
        assert!(callees_a.contains(&"B".to_string()));
        assert!(callees_a.contains(&"C".to_string()));
    }

    #[test]
    fn test_bfs_traversal() {
        let mut cg = CallGraph::new();
        cg.add_edge_raw("A", "B");
        cg.add_edge_raw("A", "C");
        cg.add_edge_raw("B", "D");
        cg.add_edge_raw("C", "D");
        cg.add_edge_raw("D", "E");

        let reachable = cg.bfs_reachable("A");
        // BFS 从 A 出发应该访问 A, B, C, D, E
        assert_eq!(reachable.len(), 5);
        assert_eq!(reachable[0], "A"); // BFS 起始节点

        let reachable_from_c = cg.bfs_reachable("C");
        assert_eq!(reachable_from_c.len(), 3); // C, D, E
    }

    #[test]
    fn test_dfs_traversal() {
        let mut cg = CallGraph::new();
        cg.add_edge_raw("A", "B");
        cg.add_edge_raw("A", "C");
        cg.add_edge_raw("B", "D");
        cg.add_edge_raw("C", "D");

        let reachable = cg.dfs_reachable("A");
        assert_eq!(reachable.len(), 4);
        assert_eq!(reachable[0], "A"); // DFS 起始节点
    }

    #[test]
    fn test_disconnected_components() {
        let mut cg = CallGraph::new();
        cg.add_edge_raw("A", "B");
        cg.add_edge_raw("X", "Y");

        let reachable_from_a = cg.bfs_reachable("A");
        assert_eq!(reachable_from_a.len(), 2); // A, B
        assert!(!reachable_from_a.contains(&"X".to_string()));

        let reachable_from_x = cg.bfs_reachable("X");
        assert_eq!(reachable_from_x.len(), 2); // X, Y
        assert!(!reachable_from_x.contains(&"A".to_string()));
    }
}

