418	/// 将 CallType 枚举转换为中文描述字符串
419	fn call_type_to_str(ct: &CallType) -> &'static str {
420	    match ct {
421	        CallType::Direct => "直接调用",
422	        CallType::Virtual => "虚函数调用",
423	        CallType::Callback => "回调调用",
424	        CallType::MacroExpansion => "宏展开调用",
425	        CallType::Unknown => "未知调用类型",
426	    }
427	}
