560	    #[test]
561	    fn test_max_depth_limit() {
562	        let mut g = CallGraph::new();
563	
564	        // 构建: a → b → c → d → e
565	        let ids = ["a", "b", "c", "d", "e"];
566	        for id in &ids {
567	            g.add_node(make_node(id, id));
568	        }
569	        for i in 0..ids.len() - 1 {
570	            g.add_edge(
571	                ids[i],
572	                ids[i + 1],
573	                make_edge(ids[i], ids[i + 1], CallType::Direct),
574	            );
575	        }
576	
577	        // max_depth = 2：只搜索两层
578	        let callees = g.trace_callees("a", 2);
579	        let max_depth = callees.iter().map(|c| c.depth).max().unwrap_or(0);
580	        assert!(max_depth <= 2, "深度不应超过 max_depth");
581	        // 应包含 b(depth=1) 和 c(depth=2)，但不包含 d(depth=3)
582	        let names: Vec<String> = callees.iter().map(|c| c.name.clone()).collect();
583	        assert!(names.contains(&"b".to_string()));
